'use strict';

// Every "what day is it" decision in the app must go through here, never
// through a client-supplied timestamp. UTC calendar day is the MVP policy
// (per-user timezone day-boundaries can replace this later without
// touching callers, since they only ever call todayString()/now()).

function now() {
  return new Date();
}

function todayString(date = now()) {
  return date.toISOString().slice(0, 10); // YYYY-MM-DD
}

function daysBetween(dateStringA, dateStringB) {
  const a = new Date(`${dateStringA}T00:00:00Z`);
  const b = new Date(`${dateStringB}T00:00:00Z`);
  return Math.round((b - a) / (1000 * 60 * 60 * 24));
}

module.exports = { now, todayString, daysBetween };
